1	import 'server-only';
2	
3	import { ClientSecretCredential } from '@azure/identity';
4	import z from 'zod';
5	
6	import { ExternalServiceError } from '@/lib/errors';
7	
8	/**
9	 * Configuration for authenticating with the Microsoft Graph API to send email.
10	 *
11	 * Requires an Entra ID (Azure AD) app registration with the `Mail.Send`
12	 * application permission, granted with admin consent.
13	 */
14	export interface GraphMailConfig {
15	    /** Azure Entra (AD) tenant ID. */
16	    tenantId: string;
17	    /** App registration client (application) ID with Mail.Send permission. */
18	    clientId: string;
19	    /** App registration client secret value. */
20	    clientSecret: string;
21	    /** The mailbox user principal name (email address) to send from. */
22	    userPrincipalName: string;
23	}
24	
25	/**
26	 * Email payload accepted by {@link sendViaGraphApi}.
27	 *
28	 * Recipients are specified as a single email string or a comma-separated list.
29	 */
30	interface GraphMailOptions {
31	    /** Primary recipient(s) — single email or comma-separated list. */
32	    to?: string;
33	    /** CC recipient(s) — single email or comma-separated list. */
34	    cc?: string;
35	    /** BCC recipient(s) — single email or comma-separated list. */
36	    bcc?: string;
37	    /** Email subject line. */
38	    subject?: string;
39	    /** HTML body content. */
40	    html?: string;
41	}
42	
43	/**
44	 * Zod schema that validates a user principal name as a valid email address.
45	 *
46	 * Used to fail fast before constructing the Graph API URL.
47	 */
48	const userPrincipalNameSchema = z.email('userPrincipalName must be a valid email address');
49	
50	/** Graph API recipient object containing an email address. */
51	interface GraphMailRecipient {
52	    emailAddress: { address: string };
53	}
54	
55	/**
56	 * Parses a comma-separated recipient string into Graph API recipient objects.
57	 *
58	 * Returns an empty array when the input is undefined or empty.
59	 *
60	 * @param value - Comma-separated email address string.
61	 * @returns Array of Graph API formatted recipients.
62	 */
63	function parseRecipients(value: string | undefined): GraphMailRecipient[] {
64	    if (!value) return [];
65	
66	    return value
67	        .split(',')
68	        .map(addr => addr.trim())
69	        .filter(addr => addr.length > 0)
70	        .map(address => ({ emailAddress: { address } }));
71	}
72	
73	/**
74	 * Sends an email via the Microsoft Graph API using application permissions.
75	 *
76	 * Uses the OAuth2 client-credentials flow to obtain a token, then calls the
77	 * Graph `sendMail` endpoint for the configured mailbox. The email is not saved
78	 * to the Sent Items folder.
79	 *
80	 * @param options - Email content and recipients.
81	 * @param config - Graph API credentials and sender configuration.
82	 * @throws {ExternalServiceError} If the Graph API request fails.
83	 */
84	export async function sendViaGraphApi(
85	    options: GraphMailOptions,
86	    config: GraphMailConfig,
87	): Promise<void> {
88	    userPrincipalNameSchema.parse(config.userPrincipalName);
89	
90	    const credential = new ClientSecretCredential(
91	        config.tenantId,
92	        config.clientId,
93	        config.clientSecret,
94	    );
95	
96	    let token: string;
97	    try {
98	        const tokenResponse = await credential.getToken(
99	            'https://graph.microsoft.com/.default',
100	        );
101	        token = tokenResponse.token;
102	    }
103	    catch (error) {
104	        throw new ExternalServiceError(
105	            `Graph API authentication failed: ${error instanceof Error ? error.message : String(error)}`,
106	            {
107	                cause: error instanceof Error ? error : undefined,
108	                details: {
109	                    tenantId: config.tenantId,
110	                    clientId: config.clientId,
111	                    userPrincipalName: config.userPrincipalName,
112	                },
113	            },
114	        );
115	    }
116	
117	    const url = `https://graph.microsoft.com/v1.0/users/${encodeURIComponent(config.userPrincipalName)}/sendMail`;
118	
119	    const response = await fetch(url, {
120	        method: 'POST',
121	        headers: {
122	            Authorization: `Bearer ${token}`,
123	            'Content-Type': 'application/json',
124	        },
125	        body: JSON.stringify({
126	            message: {
127	                subject: options.subject ?? '',
128	                body: {
129	                    contentType: 'HTML',
130	                    content: options.html ?? '',
131	                },
132	                toRecipients: parseRecipients(options.to),
133	                ccRecipients: parseRecipients(options.cc),
134	                bccRecipients: parseRecipients(options.bcc),
135	            },
136	            saveToSentItems: false,
137	        }),
138	    });
139	
140	    if (!response.ok) {
141	        let errorBody: string;
142	        try {
143	            errorBody = await response.text();
144	        }
145	        catch {
146	            errorBody = '(unable to read response body)';
147	        }
148	
149	        throw new ExternalServiceError(
150	            `Graph API sendMail failed (${response.status}): ${errorBody}`,
151	            {
152	                details: {
153	                    status: response.status,
154	                    to: options.to,
155	                    subject: options.subject,
156	                },
157	            },
158	        );
159	    }
160	}
