26	describe('sendViaGraphApi', () => {
27	    beforeEach(() => {
28	        vi.clearAllMocks();
29	        getTokenMock.mockResolvedValue({ token: 'mock-token' });
30	        vi.spyOn(global, 'fetch').mockResolvedValue(
31	            new Response(null, { status: 202 }),
32	        );
33	    });
34	
35	    it('authenticates with the correct credentials', async () => {
36	        await sendViaGraphApi(
37	            { to: 'player@example.com', subject: 'Test', html: '<p>Hi</p>' },
38	            defaultConfig,
39	        );
40	
41	        expect(clientSecretCredentialMock).toHaveBeenCalledWith(
42	            'tenant-id',
43	            'client-id',
44	            'client-secret',
45	        );
46	        expect(getTokenMock).toHaveBeenCalledWith(
47	            'https://graph.microsoft.com/.default',
48	        );
49	    });
50	
51	    it('sends a properly formatted Graph API request', async () => {
52	        await sendViaGraphApi(
53	            {
54	                to: 'player@example.com',
55	                cc: 'cc1@example.com,cc2@example.com',
56	                bcc: 'bcc@example.com',
57	                subject: 'Game Update',
58	                html: '<p>Match is on</p>',
59	            },
60	            defaultConfig,
61	        );
62	
63	        expect(fetch).toHaveBeenCalledWith(
64	            'https://graph.microsoft.com/v1.0/users/sender%40example.com/sendMail',
