66	                method: 'POST',
67	                headers: {
68	                    Authorization: 'Bearer mock-token',
69	                    'Content-Type': 'application/json',
70	                },
71	                body: JSON.stringify({
72	                    message: {
73	                        subject: 'Game Update',
74	                        body: {
75	                            contentType: 'HTML',
