77	                        },
78	                        toRecipients: [
79	                            { emailAddress: { address: 'player@example.com' } },
80	                        ],
81	                        ccRecipients: [
82	                            { emailAddress: { address: 'cc1@example.com' } },
83	                            { emailAddress: { address: 'cc2@example.com' } },
84	                        ],
85	                        bccRecipients: [
86	                            { emailAddress: { address: 'bcc@example.com' } },
87	                        ],
88	                    },
89	                    saveToSentItems: false,
90	                }),
91	            },
92	        );
93	    });
94	
95	    it('handles empty recipients gracefully', async () => {
96	        await sendViaGraphApi(
97	            { subject: 'No recipients', html: '<p>Hello</p>' },
