60	 * @returns `true` when the key matches sensitive naming conventions.
61	 */
62	const isSensitiveKey = (key: string): boolean =>
63	    SENSITIVE_KEY_PATTERN.test(key);
64	
65	/**
66	 * Clamps a numeric sample rate to the valid Sentry range [0, 1].
67	 *
68	 * @param value Candidate numeric sample rate.
69	 * @returns The clamped value.
70	 */
71	const clampSampleRate = (value: number): number =>
72	    Math.min(1, Math.max(0, value));
73	
74	/**
75	 * Parses a sample rate from an environment variable string.
76	 *
77	 * @param rawValue Raw environment variable value.
78	 * @returns Parsed and clamped sample rate, or `null` when invalid.
79	 */
80	const parseSampleRate = (rawValue: string | undefined): number | null => {
81	    if (!rawValue) {
82	        return null;
83	    }
84	
85	    const parsed = Number(rawValue);
86	    if (!Number.isFinite(parsed)) {
87	        return null;
88	    }
89	
90	    return clampSampleRate(parsed);
91	};
92	
93	/**
94	 * Resolves a Sentry sample rate from environment or defaults based on runtime.
95	 *
96	 * Resolution order:
97	 * 1. Valid numeric value from the configured environment variable.
98	 * 2. Production default when running in production.
99	 * 3. Non-production default otherwise.
100	 *
101	 * @param options Sample-rate resolution settings.
102	 * @returns A valid sample rate in [0, 1].
103	 */
104	export const resolveSentrySampleRate = (options: SampleRateOptions): number => {
105	    const fromEnv = parseSampleRate(process.env[options.envVarName]);
106	    if (fromEnv !== null) {
107	        return fromEnv;
108	    }
109	
110	    let fallback: number;
111	    if (process.env.NODE_ENV === 'production') {
112	        fallback = options.productionDefault;
113	    } else {
114	        fallback = options.nonProductionDefault;
115	    }
116	
117	    return clampSampleRate(fallback);
118	};
119	
120	/**
121	 * Redacts sensitive query-string parameters from URL strings.
122	 *
123	 * @param rawUrl Raw absolute or relative URL.
124	 * @returns URL with sensitive query parameter values replaced.
125	 */
126	const redactSensitiveQueryParams = (rawUrl: string): string => {
127	    try {
128	        const url = new URL(rawUrl, 'http://localhost');
129	        for (const [key] of url.searchParams.entries()) {
130	            if (isSensitiveKey(key)) {
131	                url.searchParams.set(key, REDACTED_VALUE);
132	            }
133	        }
134	
135	        if (rawUrl.startsWith('/')) {
136	            return `${url.pathname}${url.search}${url.hash}`;
137	        }
138	
139	        return url.toString();
140	    } catch {
141	        return rawUrl;
142	    }
143	};
144	
145	/**
146	 * Sanitizes arbitrary values for Sentry by redacting sensitive keys and
147	 * recursively traversing nested objects and arrays.
148	 *
149	 * @param value Value to sanitize.
150	 * @param depth Current recursion depth.
151	 * @param seen Set used to detect circular references.
152	 * @returns Sanitized value safe for transport to Sentry.
153	 */
154	const sanitizeValue = (
155	    value: unknown,
156	    depth: number,
157	    seen: WeakSet<object>,
158	): unknown => {
159	    if (depth >= MAX_SCRUB_DEPTH) {
160	        return value;
161	    }
162	
163	    /**
164	     * Arrays must pass this guard so they can participate in circular-reference
165	     * detection and recursive scrubbing.
166	     */
167	    if (value === null || typeof value !== 'object') {
168	        return value;
169	    }
170	
171	    if (value instanceof Date) {
172	        return value.toISOString();
173	    }
174	
175	    if (seen.has(value)) {
176	        return '[CIRCULAR]';
177	    }
178	    seen.add(value);
179	
180	    if (value instanceof Error) {
181	        return {
182	            name: value.name,
183	            message: value.message,
184	        };
185	    }
186	
187	    if (Array.isArray(value)) {
188	        return value.map((entry) => sanitizeValue(entry, depth + 1, seen));
189	    }
190	
191	    const sanitized: Record<string, unknown> = {};
192	    const objectValue = value as Record<string, unknown>;
193	    for (const [key, entry] of Object.entries(objectValue)) {
194	        if (isSensitiveKey(key)) {
195	            sanitized[key] = REDACTED_VALUE;
196	            continue;
197	        }
198	
199	        if (typeof entry === 'string' && (key === 'url' || key === 'from' || key === 'to')) {
200	            sanitized[key] = redactSensitiveQueryParams(entry);
201	            continue;
202	        }
203	
204	        sanitized[key] = sanitizeValue(entry, depth + 1, seen);
205	    }
206	
207	    return sanitized;
208	};
209	
210	/**
211	 * Scrubs Sentry event payloads before they are sent to Sentry transport.
212	 *
213	 * This function redacts sensitive key/value pairs from common top-level fields
214	 * and nested structures while preserving enough context for debugging.
215	 *
216	 * @template TEvent Generic Sentry event shape.
217	 * @param event Sentry event candidate.
218	 * @returns The same event reference after in-place sanitization.
219	 */
220	export const scrubSentryEvent = <TEvent>(event: TEvent): TEvent => {
221	    if (!isObjectRecord(event)) {
222	        return event;
223	    }
224	
225	    const seen = new WeakSet<object>();
226	    const mutableEvent = event as Record<string, unknown>;
227	
228	    if (isObjectRecord(mutableEvent.request) && typeof mutableEvent.request.url === 'string') {
229	        mutableEvent.request = {
230	            ...mutableEvent.request,
231	            url: redactSensitiveQueryParams(mutableEvent.request.url),
232	        };
233	    }
234	
235	    if (Array.isArray(mutableEvent.breadcrumbs)) {
236	        mutableEvent.breadcrumbs = mutableEvent.breadcrumbs.map((breadcrumb) =>
237	            sanitizeValue(breadcrumb, 0, seen));
238	    }
239	
240	    if (isObjectRecord(mutableEvent.extra)) {
241	        mutableEvent.extra = sanitizeValue(mutableEvent.extra, 0, seen);
242	    }
243	
244	    if (isObjectRecord(mutableEvent.tags)) {
245	        mutableEvent.tags = sanitizeValue(mutableEvent.tags, 0, seen);
246	    }
247	
248	    if (isObjectRecord(mutableEvent.user)) {
249	        mutableEvent.user = sanitizeValue(mutableEvent.user, 0, seen);
250	    }
251	
252	    return event;
253	};
